// API Contract Drift Watcher: derive schema, load prior snapshot, run a
// contract-aware diff, classify each breaking change by severity, build the alert.
// Runs once for all items. Value churn (changed values, extra array elements) is
// suppressed by design: only field paths, types, nullability and presence compare.

const MAX_DEPTH = 15;        // guard against pathological nesting
const MAX_PATHS = 4000;      // guard the Data Table cell size

const settings = $('Settings').first().json;
const endpointKey = (settings.endpointKey || '').toString().trim() || 'default-endpoint';

// 1) Pull the fetched body. The HTTP node uses Full Response, so the parsed body
//    sits under .body intact (a top-level array is not split into items).
const resp = $('Fetch the endpoint').first().json;
const body = (resp && Object.prototype.hasOwnProperty.call(resp, 'body')) ? resp.body : resp;

const rootType = jsonType(body);
if (rootType !== 'object' && rootType !== 'array') {
  // A 200 that is not JSON (an HTML login page, plain text) is not a schema we can
  // diff. Throw so the node error output routes to Skip run and the snapshot is
  // left untouched, rather than overwriting a good shape with garbage.
  throw new Error('Response body was not a JSON object or array (got ' + rootType + '). Run skipped, snapshot left unchanged.');
}

// 2) Derive the new schema: a flat map of normalized field path -> { type, nullable, required }.
const newSchema = deriveSchema(body);
const pathCount = Object.keys(newSchema).length;
if (pathCount > MAX_PATHS) {
  throw new Error('Derived schema has ' + pathCount + ' paths, over the ' + MAX_PATHS + ' guard. Point the watcher at a representative endpoint. Run skipped.');
}

// 3) Load the prior snapshot (Data Table get; zero rows on the first run).
const priorRows = $('Load prior snapshot').all()
  .map(function (r) { return r.json; })
  .filter(function (r) { return r && r.schema_object; });
const priorRow = priorRows.find(function (r) { return r.endpointKey === endpointKey; }) || null;
const isFirstRun = !priorRow;

let changes = [];
if (!isFirstRun) {
  let priorSchema = {};
  try { priorSchema = JSON.parse(priorRow.schema_object) || {}; } catch (e) { priorSchema = {}; }
  changes = diffSchemas(priorSchema, newSchema);
}

// 4) Severity rollup. A breaking change is high or medium. Low (a brand-new
//    optional field) is recorded for context but does not raise an alert on its own.
const counts = { high: 0, medium: 0, low: 0 };
for (const c of changes) { counts[c.severity] = (counts[c.severity] || 0) + 1; }
const breaking = changes.filter(function (c) { return c.severity === 'high' || c.severity === 'medium'; });
const hasBreakingChange = breaking.length > 0;
const rank = { high: 3, medium: 2, low: 1 };
let topSeverity = 'low';
for (const c of changes) { if (rank[c.severity] > rank[topSeverity]) topSeverity = c.severity; }

// 5) Build the Slack message (only used when hasBreakingChange is true).
const header = topSeverity === 'high'
  ? ':red_circle: HIGH severity API contract drift'
  : ':large_orange_circle: MEDIUM severity API contract drift';
const lines = changes.map(function (c) {
  const dot = c.severity === 'high' ? ':red_circle:' : (c.severity === 'medium' ? ':large_orange_circle:' : ':large_yellow_circle:');
  return dot + ' *' + c.kind + '* at `' + c.path + '`' + (c.detail ? ' (' + c.detail + ')' : '');
});
const alertText = header + ' on *' + endpointKey + '*\n'
  + counts.high + ' high, ' + counts.medium + ' medium, ' + counts.low + ' low\n\n'
  + lines.join('\n');

return [{
  json: {
    endpointKey: endpointKey,
    isFirstRun: isFirstRun,
    hasBreakingChange: hasBreakingChange,
    topSeverity: topSeverity,
    counts: counts,
    changes: changes,
    alertText: alertText,
    pathCount: pathCount,
    schema_object: JSON.stringify(newSchema),
    checkedAt: new Date().toISOString(),
  },
}];

// ----------------------------- helpers -----------------------------
function jsonType(v) {
  if (v === null) return 'null';
  if (v === undefined) return 'undefined';
  if (Array.isArray(v)) return 'array';
  return typeof v; // 'string' | 'number' | 'boolean' | 'object'
}

// Build path -> { type, nullable, required }. Array indices collapse to [] so
// adding/removing elements and changing values never registers as a change.
// required = the field is present in every instance of its container
// (present in all elements of an array of objects, or present on a singleton object).
function deriveSchema(root) {
  const counts = {};                 // path -> times observed (after index collapse)
  const typeSets = {};               // path -> Set of JSON types
  const nullCounts = {};             // path -> times observed as null
  const containerInstances = { '': 1 }; // container path -> number of object instances

  function record(p, value) {
    counts[p] = (counts[p] || 0) + 1;
    const t = jsonType(value);
    (typeSets[p] = typeSets[p] || new Set()).add(t);
    if (t === 'null') nullCounts[p] = (nullCounts[p] || 0) + 1;
  }

  function walk(value, p, depth) {
    if (p !== '') record(p, value);
    const t = jsonType(value);
    if (depth >= MAX_DEPTH) return;
    if (t === 'object') {
      containerInstances[p] = (containerInstances[p] || 0) + 1;
      for (const k of Object.keys(value)) {
        const childPath = p === '' ? k : p + '.' + k;
        walk(value[k], childPath, depth + 1);
      }
    } else if (t === 'array') {
      const elemPath = p + '[]';
      for (const el of value) walk(el, elemPath, depth + 1);
    }
  }

  walk(root, '', 0);

  const schema = {};
  for (const p of Object.keys(counts)) {
    const nonNull = Array.from(typeSets[p]).filter(function (x) { return x !== 'null'; });
    let type;
    if (nonNull.length === 0) type = 'null';
    else if (nonNull.length === 1) type = nonNull[0];
    else type = 'mixed(' + nonNull.sort().join('|') + ')';
    const parent = parentOf(p);
    const parentInstances = containerInstances[parent] || 1;
    schema[p] = {
      type: type,
      nullable: (nullCounts[p] || 0) > 0,
      required: counts[p] === parentInstances && parentInstances > 0,
    };
  }
  return schema;
}

function parentOf(p) {
  if (p.endsWith('[]')) return p.slice(0, -2);
  const dot = p.lastIndexOf('.');
  return dot >= 0 ? p.slice(0, dot) : '';
}

function isAncestor(anc, p) {
  if (p === anc) return false;
  return p.indexOf(anc + '.') === 0 || p.indexOf(anc + '[]') === 0;
}

function ancestorInSet(p, set) {
  for (const anc of set) { if (isAncestor(anc, p)) return true; }
  return false;
}

// Contract-aware diff. Only structural and type changes are reported; value churn
// is invisible because deriveSchema never records values or array length.
function diffSchemas(prior, next) {
  const priorPaths = Object.keys(prior);
  const nextPaths = Object.keys(next);
  const nextSet = new Set(nextPaths);
  const priorSet = new Set(priorPaths);

  const removed = priorPaths.filter(function (p) { return !nextSet.has(p); });
  const added = nextPaths.filter(function (p) { return !priorSet.has(p); });
  const common = priorPaths.filter(function (p) { return nextSet.has(p); });

  // Type change ignores null-typed sides (null is a value state, handled by nullability).
  const typeChanged = common.filter(function (p) {
    const a = prior[p].type, b = next[p].type;
    return a !== b && a !== 'null' && b !== 'null';
  });
  const removedSet = new Set(removed);
  const addedSet = new Set(added);
  const typeChangedSet = new Set(typeChanged);

  const changes = [];

  // Removed field (high). Report the top-most removed path only, and not a path
  // whose ancestor changed type (that is a consequence, not a separate break).
  for (const p of removed) {
    if (ancestorInSet(p, removedSet)) continue;
    if (ancestorInSet(p, typeChangedSet)) continue;
    changes.push({ kind: 'removed field', path: p, severity: 'high', detail: 'was ' + prior[p].type });
  }

  // Type change (high), e.g. string to number.
  for (const p of typeChanged) {
    if (ancestorInSet(p, typeChangedSet)) continue;
    changes.push({ kind: 'type change', path: p, severity: 'high', detail: prior[p].type + ' to ' + next[p].type });
  }

  // New field. Required (present in every instance of its container) is medium;
  // otherwise it is a brand-new optional field, low. Report the top-most new path only.
  for (const p of added) {
    if (ancestorInSet(p, addedSet)) continue;
    if (ancestorInSet(p, typeChangedSet)) continue;
    if (next[p].required) {
      changes.push({ kind: 'new required field', path: p, severity: 'medium', detail: 'type ' + next[p].type });
    } else {
      changes.push({ kind: 'new optional field', path: p, severity: 'low', detail: 'type ' + next[p].type });
    }
  }

  // Nullability flip (medium): present in both, never null before, null now.
  for (const p of common) {
    if (typeChangedSet.has(p) || ancestorInSet(p, typeChangedSet)) continue;
    if (!prior[p].nullable && next[p].nullable) {
      changes.push({ kind: 'nullability flip', path: p, severity: 'medium', detail: 'now returns null' });
    }
  }

  const order = { high: 0, medium: 1, low: 2 };
  changes.sort(function (x, y) { return (order[x.severity] - order[y.severity]) || x.path.localeCompare(y.path); });
  return changes;
}
